import{c as n,Q as t,j as r,m as i}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"Effective harnesses for long-running agents","description":"","frontmatter":{"title":"Effective harnesses for long-running agents","author":"Justin Young","date":"2025-11-26T00:00:00.000Z","source":"https://www.anthropic.com/engineering/effective-harnesses-for-long-running-agents","tags":["agent-harness","anthropic","research","long-running-agents"]},"headers":[],"relativePath":"research/agent-harness/references/2025-11-26-effective-harnesses-long-running-agents-anthropic.md","filePath":"research/agent-harness/references/2025-11-26-effective-harnesses-long-running-agents-anthropic.md","lastUpdated":1779894392000}'),s={name:"research/agent-harness/references/2025-11-26-effective-harnesses-long-running-agents-anthropic.md"};function a(o,e,l,c,u,h){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="effective-harnesses-for-long-running-agents" tabindex="-1">Effective harnesses for long-running agents <a class="header-anchor" href="#effective-harnesses-for-long-running-agents" aria-label="Permalink to &quot;Effective harnesses for long-running agents&quot;">​</a></h1><p><strong>Published:</strong> Nov 26, 2025<br><strong>Author:</strong> Justin Young</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Anthropic researchers developed solutions enabling AI agents to maintain consistent progress across multiple context windows when working on extended tasks. The core challenge: agents work in discrete sessions without memory of prior work, making multi-day projects difficult.</p><h2 id="the-core-problem" tabindex="-1">The Core Problem <a class="header-anchor" href="#the-core-problem" aria-label="Permalink to &quot;The Core Problem&quot;">​</a></h2><p>Long-running agents face two critical failure modes. First, they attempt excessive work simultaneously, exhausting context mid-implementation and leaving undocumented half-finished features. Second, agents may prematurely declare projects complete after observing partial progress.</p><h2 id="two-part-solution" tabindex="-1">Two-Part Solution <a class="header-anchor" href="#two-part-solution" aria-label="Permalink to &quot;Two-Part Solution&quot;">​</a></h2><p><strong>Initializer Agent:</strong> Runs once to establish the foundational environment, including:</p><ul><li>A comprehensive feature list (200+ items marked as &quot;failing&quot;)</li><li>An <code>init.sh</code> script for launching development servers</li><li>A <code>claude-progress.txt</code> file tracking work history</li><li>An initial git repository</li></ul><p><strong>Coding Agent:</strong> Executes subsequent sessions to:</p><ul><li>Review progress files and git history</li><li>Work on single features incrementally</li><li>Leave code in production-ready condition</li><li>Commit changes with descriptive messages</li></ul><h2 id="key-environmental-components" tabindex="-1">Key Environmental Components <a class="header-anchor" href="#key-environmental-components" aria-label="Permalink to &quot;Key Environmental Components&quot;">​</a></h2><p>The feature list uses JSON format with detailed requirements. As researchers note, &quot;the model is less likely to inappropriately change or overwrite JSON files compared to Markdown files.&quot;</p><p>Testing proved essential. Claude performed better when given explicit browser automation tools (Puppeteer) to verify features end-to-end as human users would, rather than relying solely on unit tests.</p><h2 id="session-structure" tabindex="-1">Session Structure <a class="header-anchor" href="#session-structure" aria-label="Permalink to &quot;Session Structure&quot;">​</a></h2><p>Each session begins with standardized steps: checking directory location, reading progress files, reviewing git logs, examining the feature list, and running basic verification tests before implementing new features.</p><h2 id="future-directions" tabindex="-1">Future Directions <a class="header-anchor" href="#future-directions" aria-label="Permalink to &quot;Future Directions&quot;">​</a></h2><p>Researchers question whether multi-agent architectures with specialized agents (testing, QA, cleanup) might outperform single general-purpose agents. Additionally, these findings currently apply to web development but may generalize to scientific research or financial modeling.</p>',19)])])}const p=n(s,[["render",a]]);export{d as __pageData,p as default};
